oldWay:
/* Custom properties can't be transitioned —
   the browser treats them as opaque strings */
.box {
  --hue: 30;
  background: oklch(65% 0.22 var(--hue));
  transition: --hue 0.4s; /* has no effect */
}
.box:hover {
  --hue: 260; /* jumps instantly */
}

modernWay:
@property --hue {
  syntax: '<number>';
  initial-value: 30;
  inherits: false;
}

.box {
  background: oklch(65% 0.22 var(--hue));
  transition: --hue 0.4s;
}
.box:hover {
  --hue: 260; /* now animates smoothly */
}

startingCSS:
.demo {
  display: flex;
  gap: 1.5rem;
  padding: 1.5rem;
  background: #0f172a;
  border-radius: 12px;
}

.box {
  flex: 1;
  height: 140px;
  border-radius: 10px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: 600;
  font-size: 0.9rem;
  text-align: center;
  gap: 0.4rem;
  cursor: pointer;
}

.box small {
  font-size: 0.7rem;
  opacity: 0.75;
  font-weight: 400;
}

/* Untyped — transition has no effect, color jumps on hover */
.untyped {
  --hue: 30;
  background: oklch(65% 0.22 var(--hue));
  transition: --hue 0.5s ease;
}
.untyped:hover { --hue: 260; }

/* Typed — needs @property to enable the transition */
.typed {
  --typed-hue: 30;
  background: oklch(65% 0.22 var(--typed-hue));
  transition: --typed-hue 0.5s ease;
}
.typed:hover { --typed-hue: 260; }

